{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires reconstructing a sequence of operations. This is best solved by analyzing the tree structure (degrees and parent-child relationships) and simulating the reverse process or a greedy construction. The decomposition focuses on validating the tree properties, identifying the necessary merge operations, and verifying the sequence.",
  "helpers": [
    {
      "label": "validate_tree_structure",
      "instructions": "Verify that the input initial tree and final tree are valid rooted trees. Check that the number of nodes is consistent and that the parent-child relationships do not form cycles. Identify the degree of each node in both trees."
    },
    {
      "label": "identify_merge_candidates",
      "instructions": "Compare the adjacency lists of the initial tree and the final tree. Identify which edges exist in the initial tree but are absent in the final tree. These missing edges represent the 'merges' that must have occurred. For each node, determine which siblings were merged into a single child."
    },
    {
      "label": "check_merge_feasibility",
      "instructions": "For each node in the final tree, check if its children can be formed by merging a subset of the children of the corresponding node in the initial tree. Ensure that the order of siblings is preserved according to the problem's constraints (if any) and that no node is used in more than one merge operation."
    },
    {
      "label": "construct_operation_sequence",
      "instructions": "Using the identified merge candidates, generate a valid sequence of operations. A merge operation typically involves taking two sibling nodes and making one the parent of the other (or similar, depending on the specific 'merge' definition in the problem). Ensure the sequence follows a topological order (e.g., bottom-up) so that a node is only merged after its descendants are processed."
    },
    {
      "label": "verify_final_sequence",
      "instructions": "Simulate the proposed sequence of operations starting from the initial tree. Verify that the resulting tree structure matches the target final tree exactly."
    }
  ],
  "synthesis_brief": "The parent will collect the validated merge candidates and the constructed sequence. It will then use the verification step to ensure the sequence is correct. If the simulation matches the target tree, the sequence is returned as the FINAL_ANSWER; otherwise, it will signal a failure in the construction logic."
}
```

